INSERT INTO `settings` (`setting_key`, `setting_value`) VALUES ('heroSlides', '[{"id":1,"title":"Nurturing Global Leaders","titleAr":"تنشئة قادة عالميين","subtitle":"Legacy of Excellence","subtitleAr":"إرث من التميز","description":"Empowering the next generation with world-class education and values.","descriptionAr":"تمكين الجيل القادم من خلال تعليم وقيم ذات مستوى عالمي.","image":"/nano-banana-1771792169108.webp"},{"id":2,"title":"Excellence in Education","titleAr":"التميز في التعليم","subtitle":"Leading National Institutes in Egypt","subtitleAr":"المعاهد القومية الرائدة في مصر","description":"Empowering future generations with knowledge and values.","descriptionAr":"تمكين أجيال المستقبل بالمعرفة والقيم.","image":"/nano-banana-1771778144311.png"},{"id":3,"title":"Modern Learning","titleAr":"تعلم حديث","subtitle":"Advanced Curriculum & Facilities","subtitleAr":"مناهج ومرافق متطورة","description":"Preparing students for a globalized world.","descriptionAr":"إعداد الطلاب لعالم معولم.","image":"/nano-banana-1771806330134.png"}]');
INSERT INTO `settings` (`setting_key`, `setting_value`) VALUES ('aboutData', '{"name":"Ahmed Eid","nameAr":"أحمد عيد","role":"Chairman of NIS","roleAr":"رئيس المعاهد القومية","desc":"Leading the future of national education in Egypt through excellence and innovation.","descAr":"قيادة مستقبل التعليم القومي في مصر من خلال التميز والابتكار.","quote":"Education is the most powerful weapon which you can use to change the world.","quoteAr":"التعليم هو أقوى سلاح يمكنك استخدامه لتغيير العالم.","points":["40+ Years of Excellence","Modern Curriculum","Expert Faculty","Advanced Facilities"],"pointsAr":["أكثر من ٤٠ عاماً من التميز","مناهج حديثة","أعضاء هيئة تدريس خبراء","مرافق متقدمة"],"chairmanImage":"https://images.unsplash.com/photo-1560250097-0b93528c311a?q=80&w=600&auto=format&fit=crop","storyTitle":"Crafting the Future Since 1995","storyTitleAr":"صياغة المستقبل منذ عام ١٩٩٥","storyDesc":"Our journey began with a simple yet profound vision: to provide world-class education that respects our national roots while embracing global innovation.","storyDescAr":"بدأت رحلتنا برؤية بسيطة ولكن عميقة: تقديم تعليم عالمي يحترم جذورنا الوطنية مع تبني الابتكار العالمي.","missionTitle":"Our Mission","missionTitleAr":"رسالتنا","missionDesc":"To empower students with the knowledge, skills, and values needed to thrive in an ever-changing world, fostering a new generation of Egyptian leaders.","missionDescAr":"تمكين الطلاب بالمعرفة والمهارات والقيم اللازمة للازدهار في عالم دائم التغير، ورعاية جيل جديد من القادة المصريين.","visionTitle":"Our Vision","visionTitleAr":"رؤيتنا","visionDesc":"To be the benchmark for educational excellence in Egypt, recognized for producing graduates who are intellectually curious and socially responsible.","visionDescAr":"أن نكون المعيار للتميز التعليمي في مصر، والمعترف بنا في تخريج طلاب يتسمون بالفضول الفكري والمسؤولية الاجتماعية.","values":[{"title":"Excellence","titleAr":"التميز","desc":"Striving for the highest standards in everything we do.","descAr":"السعي لتحقيق أعلى المعايير في كل ما نقوم به."},{"title":"Innovation","titleAr":"الابتكار","desc":"Embracing new ideas and creative problem solving.","descAr":"تبني الأفكار الجديدة وحل المشكلات بطرق إبداعية."},{"title":"Integrity","titleAr":"النزاهة","desc":"Maintaining honest and ethical conduct at all times.","descAr":"الحفاظ على السلوك الصادق والأخلاقي في جميع الأوقات."},{"title":"Community","titleAr":"المجتمع","desc":"Fostering a supportive and inclusive learning environment.","descAr":"تعزيز بيئة تعليمية داعمة وشاملة للجميع."}]}');
