INSERT INTO `settings` (`setting_key`, `setting_value`) VALUES ('homeData', '{"trustedTitle":"Trusted by Generations of","trustedTitleAr":"أجيال تثق في","trustedHighlight":"Egyptian Families","trustedHighlightAr":"العائلات المصرية","trustedDesc":"Providing high-quality national education that builds character and prepares students for a successful future.","trustedDescAr":"تقديم تعليم قومي عالي الجودة يبني الشخصية ويعد الطلاب لمستقبل ناجح.","trustedCTA":"Discover Our Schools","trustedCTAAr":"اكتشف مدارسنا","gatewayTitle":"Your Gateway to","gatewayTitleAr":"بوابتك إلى","gatewayHighlight":"Educational Excellence","gatewayHighlightAr":"التميز التعليمي","gatewayDesc":"Join thousands of students across Egypt in our network of specialized national institutes.","gatewayDescAr":"انضم إلى آلاف الطلاب في جميع أنحاء مصر في شبكة معاهدنا القومية المتخصصة.","gatewayCTA":"View Map","gatewayCTAAr":"عرض الخريطة","mapImage":"/nano-banana-17717977008341.webp","ctaTitle":"Join the NIS Family Today","ctaTitleAr":"انضم لعائلة المعاهد القومية اليوم","ctaDesc":"Become part of Egypt''s leading educational network and shape your child''s future.","ctaDescAr":"كن جزءاً من شبكة التعليم الرائدة في مصر وشكل مستقبل طفلك.","ctaButton":"Register Interest","ctaButtonAr":"سجل اهتمامك"}');
